def autogen_vex_loop_guard(conversation_history, max_turns=50):
    # Vex detects AutoGen-specific loop patterns
    loop_check = vex.scan({
        'content': conversation_history[-10:],
        'metadata': {'agent_count': len(conversation_history[0]['agents'])},
        'checks': ['conversation_loop', 'token_budget_exceeded']
    })

    if loop_check['risk_score'] > 0.8 or len(conversation_history) > max_turns:
        return {
            'terminate': True,
            'reason': 'Infinite loop detected - potential SOX reporting delay',
            'disclaimer': 'Conversation terminated per compliance policy.'
        }
    return {'continue': True}

